@typeparam TItem
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private InfiniteScrollInterop? _interop;
    private bool _isLoading;
    private bool _hasMoreChanged;

    [EditorRequired]
    [Parameter]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [EditorRequired]
    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    [EditorRequired]
    [Parameter]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override void OnParametersSet()
    {
        _hasMoreChanged = true;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new InfiniteScrollInterop(JS);
            await _interop.InitializeAsync(_sentinelRef, DotNetObjectReference.Create(this));
        }
        else if (_hasMoreChanged && !HasMore && _interop is not null)
        {
            _hasMoreChanged = false;
            await _interop.DisconnectAsync();
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        await InvokeAsync(StateHasChanged);

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        await InvokeAsync(StateHasChanged);
    }

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        if (_interop is not null)
            await _interop.DisposeAsync();
    }
}

