    // Overload that accepts any DotNetObjectReference via the non-generic base
    public async ValueTask InitializeAsync<TItem>(
        ElementReference sentinel, DotNetObjectReference<InfiniteScrollList<TItem>> dotNetRef)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitMethod, sentinel, dotNetRef);
    }

    public async ValueTask DisconnectAsync()
    {
        if (_module is not null)
            await _module.InvokeVoidAsync(DisconnectMethod);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
