const ON_SENTINEL_VISIBLE = 'OnSentinelVisible';

class InfiniteScrollObserver {
    #observer;
    #dotNetRef;

    constructor(sentinel, dotNetRef) {
        this.#dotNetRef = dotNetRef;
        this.#observer = new IntersectionObserver(
            async (entries) => {
                if (entries[0].isIntersecting) {
                    try {
                        await this.#dotNetRef.invokeMethodAsync(ON_SENTINEL_VISIBLE);
                    } catch { /* circuit disconnected */ }
                }
            },
            { rootMargin: '0px 0px 200px 0px' }
        );
        this.#observer.observe(sentinel);
    }

    disconnect() {
        this.#observer.disconnect();
    }

    dispose() {
        this.#observer.disconnect();
        this.#dotNetRef = null;
    }
}

let instance;

export function initialize(sentinel, dotNetRef) {
    instance = new InfiniteScrollObserver(sentinel, dotNetRef);
}

export function disconnect() {
    instance?.disconnect();
}

export function dispose() {
    instance?.dispose();
    instance = null;
}

